package genxsolution.vms.vmsbackend.maintenance_management.breakdown_record.service;
import genxsolution.vms.vmsbackend.maintenance_management.exception.MaintenanceResourceNotFoundException; import genxsolution.vms.vmsbackend.maintenance_management.breakdown_record.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.breakdown_record.mapper.BreakdownRecordMapper; import genxsolution.vms.vmsbackend.maintenance_management.breakdown_record.repository.BreakdownRecordRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class BreakdownRecordService { private final BreakdownRecordRepository repository; private final BreakdownRecordMapper mapper; public BreakdownRecordService(BreakdownRecordRepository repository,BreakdownRecordMapper mapper){this.repository=repository;this.mapper=mapper;} public List<BreakdownRecordResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public BreakdownRecordResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("BreakdownRecord", String.valueOf(id))); } public BreakdownRecordResponse create(BreakdownRecordUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public BreakdownRecordResponse update(UUID id,BreakdownRecordUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("BreakdownRecord", String.valueOf(id))); } public void delete(UUID id){ if(!repository.delete(id)) throw new MaintenanceResourceNotFoundException("BreakdownRecord", String.valueOf(id)); } }
